                              <button key={reaction} className="reaction-btn" onClick={() => reactToPost(post._id, reaction)}>
                                {reaction === 'like' && '👍'}
                                {reaction === 'love' && '❤️'}
                                {reaction === 'haha' && '😂'}
                                {reaction === 'wow' && '😮'}
                                {reaction === 'sad' && '😢'}
                                {reaction === 'angry' && '😡'}
                              </button>
